import React from 'react';
import { useAuth } from '../context/AuthContext';
import Layout from '../components/Layout';
import { useNavigate } from 'react-router-dom';

const Dashboard = () => {
    const { user } = useAuth();
    const navigate = useNavigate();

    return (
        <Layout>
            <div className="bg-white shadow-sm rounded-lg p-6">
                <h1 className="text-2xl font-bold mb-6">
                    Bienvenido, {user?.name}
                </h1>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {/* Tarjeta de Solicitudes Pendientes */}
                    <div className="bg-blue-50 p-6 rounded-lg">
                        <h3 className="text-lg font-semibold text-blue-700 mb-2">
                            Solicitudes Pendientes
                        </h3>
                        <p className="text-3xl font-bold text-blue-900">0</p>
                    </div>

                    {/* Tarjeta de Solicitudes Completadas */}
                    <div className="bg-green-50 p-6 rounded-lg">
                        <h3 className="text-lg font-semibold text-green-700 mb-2">
                            Solicitudes Completadas
                        </h3>
                        <p className="text-3xl font-bold text-green-900">0</p>
                    </div>

                    {/* Tarjeta de Solicitudes Rechazadas */}
                    <div className="bg-red-50 p-6 rounded-lg">
                        <h3 className="text-lg font-semibold text-red-700 mb-2">
                            Solicitudes Rechazadas
                        </h3>
                        <p className="text-3xl font-bold text-red-900">0</p>
                    </div>
                </div>

                {/* Acciones Rápidas */}
                <div className="mt-8">
                    <h2 className="text-xl font-semibold mb-4">Acciones Rápidas</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {user?.role === 'comercial' && (
                            <button 
                                onClick={() => navigate('/nuevo-cliente')}
                                className="p-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                            >
                                Nueva Solicitud de Cliente
                            </button>
                        )}
                        <button 
                            onClick={() => navigate('/mis-solicitudes')}
                            className="p-4 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors"
                        >
                            Ver Mis Solicitudes
                        </button>
                    </div>
                </div>
            </div>
        </Layout>
    );
};

export default Dashboard;
